1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	};
8	
9	type Item = { type: string };
10	type Step = { op: string; items: Item[] };
11	type Input = { steps: Step[] };
12	
13	const itemPremium = (item: Item): number => {
14	  const base = BASE_PREMIUMS[item.type] ?? 0;
15	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
16	  return base + firstInsuranceSurcharge;
17	};
18	
19	const quotePremium = (step: Step): number => {
20	  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
21	  return Math.ceil(itemsTotal) + PROCESSING_FEE;
22	};
23	
24	export const runScenario = (input: unknown): unknown => {
25	  const { steps } = input as Input;
26	  const results = steps.map((step) => ({ premium: quotePremium(step) }));
27	  return { results };
28	};
